<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bots — 24 Pathfinders</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --wall: #8b949e;
    --accent: #58a6ff;
    --good: #3fb950;
    --text: #e6edf3;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: radial-gradient(circle at 50% 20%, #16202e 0%, var(--bg) 70%);
    color: var(--text);
    font-family: "Segoe UI", system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 24px 12px;
  }
  h1 {
    font-size: 20px;
    font-weight: 600;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin: 0 0 16px;
    color: var(--accent);
  }
  #hud {
    display: flex;
    gap: 14px;
    align-items: center;
    background: var(--panel);
    border: 1px solid #30363d;
    border-radius: 12px;
    padding: 10px 18px;
    margin-bottom: 16px;
    box-shadow: 0 4px 18px rgba(0,0,0,0.45);
  }
  .hud-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 110px;
  }
  .hud-label {
    font-size: 10px;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: #8b949e;
  }
  .hud-value {
    font-size: 20px;
    font-variant-numeric: tabular-nums;
    font-weight: 600;
  }
  #completed { color: var(--good); }
  #timer { color: var(--accent); }
  #reset {
    background: linear-gradient(180deg, #238636, #1a6a2b);
    color: #fff;
    border: 1px solid #2ea043;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: filter 0.15s, transform 0.1s;
  }
  #reset:hover { filter: brightness(1.15); }
  #reset:active { transform: scale(0.96); }
  #maze {
    width: 546px;
    height: 546px;
    max-width: 96vw;
    max-height: 96vw;
